from math import prod
from itertools import islice
from heapq import heappop, heappush
from sympy import nextprime, factorint
def A365308_gen(): # generator of terms if the first n terms are desired.
    h, hset = [1], {1}
    while True:
        yield (m:=heappop(h))
        ps = factorint(m)
        if m==1:
            heappush(h,36)
            hset.add(36)
        else:
            mp = m*prod(ps.keys())
            if mp not in hset:
                heappush(h,mp)
                hset.add(mp)
            mp = m*nextprime(p:=max(ps.keys()))**ps[p]
            if mp not in hset:
                heappush(h,mp)
                hset.add(mp)
A365308_list = list(islice(A365308_gen(),50)) # _Chai Wah Wu_, Mar 28 2026

